// Compute previous calendar month (reporting period)
const now = new Date();
const firstOfThisMonth = new Date(now.getFullYear(), now.getMonth(), 1);
const lastOfPrevMonth = new Date(firstOfThisMonth.getTime() - 1);

const reportYear = lastOfPrevMonth.getFullYear();
const reportMonthIndex = lastOfPrevMonth.getMonth(); // 0-11
const reportMonth = reportMonthIndex + 1; // 1-12

const monthNames = [
  'January','February','March','April','May','June',
  'July','August','September','October','November','December'
];

const reportMonthName = monthNames[reportMonthIndex];

const periodStart = new Date(reportYear, reportMonthIndex, 1);
const periodEnd = new Date(reportYear, reportMonthIndex + 1, 0);

const fmt = (d) => d.toISOString().slice(0, 10);

return [{
  json: {
    generated_at: now.toISOString(),
    report_year: reportYear,
    report_month: reportMonth,
    report_month_name: reportMonthName,
    period_start: fmt(periodStart),
    period_end: fmt(periodEnd)
  }
}];

// Build the monthly reporting request for the AI Agent
const meta = $json;

const chatInput = `Create the **Monthly Financial Standing Report** for NovaCart for **${meta.report_month_name} ${meta.report_year}** (period ${meta.period_start} to ${meta.period_end}).\n\n` +
`Requirements:\n` +
`1) Use the Internal Finance vector store tool to pull internal performance (sales, units, revenue, margins, anomalies) for the month.\n` +
`2) Use the External Market Reports vector store tool to pull market trends, competitor moves, macro conditions, and any relevant category insights.\n` +
`3) Correlate internal performance with external conditions. Explicitly call out what likely drove results.\n` +
`4) Provide a clear narrative plus tables where appropriate.\n` +
`5) Output MUST be valid HTML (no Markdown, no code fences).\n\n` +
`Focus on decision-useful insights for executives. If any key data is missing, state assumptions and data gaps clearly.`;

const sessionId = `monthly_finance_report_${meta.report_year}_${String(meta.report_month).padStart(2,'0')}`;

return [{ json: { ...meta, sessionId, chatInput, text: chatInput } }];

// Prepare email payload (compatible with n8n Code node v2)

// 1) Pull the reporting period metadata from the earlier node
const metaItems = $items('Set Reporting Period');
const meta = (metaItems?.[0]?.json) ?? {};

// 2) The AI Agent output is the input to THIS node
const agentOut = $input.first().json;

// Try common output fields (Agent nodes vary by version/config)
let html =
  agentOut.output ??
  agentOut.text ??
  agentOut.response ??
  agentOut.answer ??
  agentOut.result ??
  agentOut;

// Ensure it's a string
if (typeof html !== 'string') {
  html = JSON.stringify(html, null, 2);
}

// Strip accidental Markdown code fences if the model wrapped HTML
html = html.replace(/^```(?:html)?\s*/i, '').replace(/\s*```$/i, '');

// If it doesn't look like HTML, wrap in <pre> so the email still renders legibly
if (!/<[a-z][\s\S]*>/i.test(html)) {
  const escape = (s) => s
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
  html = `<pre style="white-space: pre-wrap; font-family: ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, 'Liberation Mono', 'Courier New', monospace;">${escape(html)}</pre>`;
}

const month = meta.report_month_name ?? '';
const year = meta.report_year ?? '';
const subject = `NovaCart Monthly Financial Standing Report — ${month} ${year}`.trim();

return [{
  json: {
    ...meta,
    report_subject: subject,
    report_html: html
  }
}];
